/**
 * Image optimization utilities for Next.js.
 *
 * Provides helpers for srcset generation, responsive sizing,
 * blur placeholder generation, and image CDN URL building.
 *
 * @module lib/performance/image-optimization
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Supported image widths for responsive srcset. */
export type ImageBreakpoint = 640 | 750 | 828 | 1080 | 1200 | 1920 | 2048 | 3840;

/** Image format preference. */
export type ImageFormat = 'webp' | 'avif' | 'jpeg' | 'png';

/** Options for generating responsive image attributes. */
export interface ResponsiveImageOptions {
  /** Base URL or path of the image. */
  src: string;
  /** Alt text for accessibility. */
  alt: string;
  /** Width breakpoints to generate. Defaults to standard set. */
  widths?: ImageBreakpoint[];
  /** Sizes attribute value. Defaults to '100vw'. */
  sizes?: string;
  /** Preferred format. Defaults to 'webp'. */
  format?: ImageFormat;
  /** Image quality 1-100. Defaults to 75. */
  quality?: number;
  /** Loading strategy. Defaults to 'lazy'. */
  loading?: 'lazy' | 'eager';
  /** Whether to add fetchpriority="high". Defaults to false. */
  priority?: boolean;
}

/** Generated responsive image attributes. */
export interface ResponsiveImageAttrs {
  src: string;
  srcSet: string;
  sizes: string;
  alt: string;
  loading: 'lazy' | 'eager';
  decoding: 'async' | 'sync';
  fetchPriority?: 'high' | 'low' | 'auto';
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/** Standard responsive width breakpoints. */
export const DEFAULT_WIDTHS: ImageBreakpoint[] = [640, 750, 828, 1080, 1200, 1920];

/** Quality presets. */
export const QUALITY_PRESETS = {
  thumbnail: 60,
  standard: 75,
  high: 85,
  lossless: 100,
} as const;

export type QualityPreset = keyof typeof QUALITY_PRESETS;

/** Maximum image file size recommendations (bytes). */
export const SIZE_BUDGETS = {
  hero: 200_000,        // 200 KB
  thumbnail: 30_000,    // 30 KB
  inline: 10_000,       // 10 KB — consider inline Base64
  avatar: 15_000,       // 15 KB
} as const;

export type SizeBudget = keyof typeof SIZE_BUDGETS;

// ---------------------------------------------------------------------------
// Pure helpers
// ---------------------------------------------------------------------------

/**
 * Build a Next.js image loader URL for a given width.
 * Works with Vercel's built-in image optimization.
 */
export function buildImageUrl(
  src: string,
  width: number,
  quality: number = 75,
): string {
  // External URLs — use Next.js image proxy
  if (src.startsWith('http://') || src.startsWith('https://')) {
    return `/_next/image?url=${encodeURIComponent(src)}&w=${width}&q=${quality}`;
  }
  // Internal paths — use Next.js image proxy
  return `/_next/image?url=${encodeURIComponent(src)}&w=${width}&q=${quality}`;
}

/**
 * Generate a srcSet string from an array of widths.
 */
export function buildSrcSet(
  src: string,
  widths: ImageBreakpoint[],
  quality: number = 75,
): string {
  return widths
    .map((w) => `${buildImageUrl(src, w, quality)} ${w}w`)
    .join(', ');
}

/**
 * Build complete responsive image attributes.
 */
export function buildResponsiveAttrs(opts: ResponsiveImageOptions): ResponsiveImageAttrs {
  const widths = opts.widths ?? DEFAULT_WIDTHS;
  const quality = opts.quality ?? 75;
  const loading = opts.loading ?? 'lazy';
  const sizes = opts.sizes ?? '100vw';

  // Largest width as the default src
  const maxWidth = Math.max(...widths);

  return {
    src: buildImageUrl(opts.src, maxWidth, quality),
    srcSet: buildSrcSet(opts.src, widths, quality),
    sizes,
    alt: opts.alt,
    loading,
    decoding: loading === 'lazy' ? 'async' : 'sync',
    ...(opts.priority ? { fetchPriority: 'high' as const } : {}),
  };
}

/**
 * Generate a tiny SVG blur placeholder (data URI).
 * This creates a minimal blurred rectangle for LQIP (Low Quality Image Placeholder).
 */
export function generateBlurPlaceholder(
  width: number = 8,
  height: number = 8,
  color: string = '#e2e8f0',
): string {
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}"><rect width="${width}" height="${height}" fill="${color}"/></svg>`;
  const encoded = Buffer.from(svg).toString('base64');
  return `data:image/svg+xml;base64,${encoded}`;
}

/**
 * Determine optimal sizes attribute based on component context.
 */
export function computeSizes(
  layout: 'full' | 'half' | 'third' | 'quarter' | 'thumbnail',
): string {
  switch (layout) {
    case 'full':       return '100vw';
    case 'half':       return '(max-width: 768px) 100vw, 50vw';
    case 'third':      return '(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw';
    case 'quarter':    return '(max-width: 768px) 50vw, 25vw';
    case 'thumbnail':  return '(max-width: 768px) 25vw, 150px';
  }
}

/**
 * Check if an image is above the size budget for its category.
 */
export function isOverBudget(
  fileSizeBytes: number,
  category: SizeBudget,
): boolean {
  return fileSizeBytes > SIZE_BUDGETS[category];
}

/**
 * Estimate savings from format conversion.
 */
export function estimateFormatSavings(
  originalSizeBytes: number,
  targetFormat: ImageFormat,
): number {
  const reductionFactors: Record<ImageFormat, number> = {
    avif: 0.50,   // ~50% reduction vs JPEG
    webp: 0.30,   // ~30% reduction vs JPEG
    jpeg: 0,
    png:  0,
  };
  return Math.round(originalSizeBytes * reductionFactors[targetFormat]);
}

/**
 * Suggest the best format for an image based on content type.
 */
export function suggestFormat(
  hasTransparency: boolean,
  isPhoto: boolean,
): ImageFormat {
  if (hasTransparency) return 'webp';
  if (isPhoto) return 'avif';
  return 'webp';
}
